        else c_coord++;

        // Ensure coordinates stay within 4x4 bounds (though directions guarantee this for 6 moves)
        if (r_coord > 3 || c_coord > 3) break; 

        const k = r_coord * 4 + c_coord;
        K.push(k);
    }

